/**
 * Fillamentum Product Seed Data
 * Parsed from manufacturer CSV export - 203 products across ~20 product lines
 * Premium Czech filament manufacturer known for exceptional color consistency
 */

export interface FillamentumSeedProduct {
  material: string;        // CSV Material column (e.g., "PLA Extrafill", "Flexfill TPU")
  filamentName: string;    // Full product title from CSV
  productUrl: string;      // Direct Shopify product URL
  color: string | null;    // Extracted color name (null for single-color products)
  imageUrl: string | null; // Shopify CDN image URL (with fixed protocol)
  colorHex: string | null; // Hex code if provided in CSV (null if N/A or empty)
}

// Helper to fix image URLs from CSV (convert escaped slashes to proper https URLs)
function fixImageUrl(rawUrl: string | null): string | null {
  if (!rawUrl) return null;
  // Convert "\\/\\/" to "https://"
  return 'https:' + rawUrl.replace(/\\\//g, '/');
}

// Helper to normalize hex codes from CSV
function normalizeHex(hex: string | null | undefined): string | null {
  if (!hex || hex === 'N/A' || hex.trim() === '') return null;
  const cleaned = hex.trim();
  if (cleaned.startsWith('#') && cleaned.length >= 7) return cleaned;
  return null;
}

