// Filter out samples and bundles from the seed
export const FILLAMENTUM_FILTERED_SEED = FILLAMENTUM_PRODUCT_SEED.filter(p => {
  const title = p.filamentName.toLowerCase();
  // Exclude samples
  if (/\d+\s*m\s*sample/i.test(title)) return false;
  // Exclude bundles
  if (/bundle/i.test(title)) return false;
  // Exclude LockPAd accessories
  if (/lockpad/i.test(title)) return false;
  return true;
});

// Export count for reference
export const FILLAMENTUM_SEED_COUNT = FILLAMENTUM_FILTERED_SEED.length;
